mapper.select:


     and oper_id = #{operId}
     and title = #{title}
     and business_type = #{businessType}
     and method = #{method}
     and request_method = #{requestMethod}
     and operator_type = #{operatorType}
     and oper_name = #{operName}
     and dept_name = #{deptName}
     and oper_url = #{operUrl}
     and oper_ip = #{operIp}
     and oper_location = #{operLocation}
     and oper_param = #{operParam}
     and json_result = #{jsonResult}
     and status = #{status}
     and error_msg = #{errorMsg}
     and oper_user_id = #{operUserId}
     and oper_user_security_id = #{operUserSecurityId}
     and oper_user_security_name = #{operUserSecurityName}
     and oper_object_security_name = #{operObjectSecurityName}
     and oper_object_security_id = #{operObjectSecurityId}
     and oper_object_id = #{operObjectId}
     and oper_object_name = #{operObjectName}
     and oper_user_security_value = #{operUserSecurityValue}
     and oper_object_security_value = #{operObjectSecurityValue}



        and oper_time between
        str_to_date(concat(#{beginTime}, ' 00:00:00'), '%Y-%m-%d %H:%i:%s')
        and
        str_to_date(concat(#{endTime}, ' 23:59:59'), '%Y-%m-%d %H:%i:%s')



        and oper_time >= str_to_date(concat(#{beginTime}, ' 00:00:00'), '%Y-%m-%d %H:%i:%s')



        and oper_time <= str_to_date(concat(#{endTime}, ' 23:59:59'), '%Y-%m-%d %H:%i:%s')


order by oper_time
